    for (int i = 1; i < len; i++) {
        if (arr[i] > m) m = arr[i];
    }
    return m;
}
int main() {
    int arr[] = {3, 7, 2, 9, 4};
    printf("%d\n", max(arr, 5));
    return 0;
}

output:
