    $m = arr[0]
    ~i = 1; i < len; i = i + 1 {
        ? arr[i] > m {
            m = arr[i]
        }
    }
    ^ m
}
# {
    $arr = [3, 7, 2, 9, 4]
    ! max(arr, 5)
}

