% bubble_sort(arr, n) {
    ~i = 0; i < n - 1; i = i + 1 {
        ~j = 0; j < n - i - 1; j = j + 1 {
            ? arr[j] > arr[j + 1] {
                $tmp = arr[j]
                arr[j] = arr[j + 1]
                arr[j + 1] = tmp
            }
        }
    }
}
# {
    $arr = [64, 34, 25, 12, 22]
    bubble_sort(arr, 5)
    ! arr
}

output:
#include <stdio.h>
void bubble_sort(int arr[], int n) {
    for (int i = 0; i < n - 1; i++) {
        for (int j = 0; j < n - i - 1; j++) {
            if (arr[j] > arr[j + 1]) {
                int tmp = arr[j];
                arr[j] = arr[j + 1];
                arr[j + 1] = tmp;
            }
        }
    }
}
int main() {
    int arr[] = {64, 34, 25, 12, 22};
    bubble_sort(arr, 5);
    for (int i = 0; i < 5; i++) printf("%d ", arr[i]);
    return 0;
}

