#include <stdio.h>
int count_digits(int n) {
    if (n == 0) return 1;
    int c = 0;
    while (n > 0) { n /= 10; c++; }
    return c;
}
int main() {
    printf("%d\n", count_digits(5020));
    return 0;
}

fn count_digits(mut n: i32) -> i32 {
    if n == 0 { return 1; }
    let mut c = 0;
    while n > 0 { n /= 10; c += 1; }
    c
}
fn main() {
    println!("{}", count_digits(5020));
}

fn count_digits(n: Int) -> Int:
    if n == 0: return 1
    var x = n
    var c = 0
    while x > 0:
        x = x // 10
        c += 1
    return c
fn main():
    print(count_digits(5020))

