#include <stdio.h>
long modpow(long b, long e, long m) {
    long r = 1 % m;
    b %= m;
    while (e > 0) {
        if (e & 1) r = (r * b) % m;
        b = (b * b) % m;
        e >>= 1;
    }
    return r;
}
int main() {
    printf("%ld\n", modpow(3, 4, 17));
    return 0;
}

fn modpow(mut b: i64, mut e: i64, m: i64) -> i64 {
    let mut r = 1 % m;
    b %= m;
    while e > 0 {
        if e & 1 == 1 { r = r * b % m; }
        b = b * b % m;
        e >>= 1;
    }
    r
}
fn main() {
    println!("{}", modpow(3, 4, 17));
}

fn modpow(b: Int, e: Int, m: Int) -> Int:
    var r = 1 % m
    var x = b % m
    var ee = e
    while ee > 0:
        if ee % 2 == 1:
            r = (r * x) % m
        x = (x * x) % m
        ee = ee // 2
    return r
fn main():
    print(modpow(3, 4, 17))

